const raw = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content || '';
let parsed;
try { parsed = JSON.parse(raw); } catch (e) { parsed = { emotion: 'melancholy', city: 'lisbon' }; }

const biasMessages = {
  lisbon: 'Your subconscious kept choosing Lisbon. Every image pulled you toward something slow, beautiful, and a little melancholy.',
  tokyo: 'Your choices point to Tokyo — the weight of a city that never stops, and the loneliness only a crowd can create.',
  berlin: 'Berlin keeps appearing in your instincts. Creative restlessness. The need to make something out of the noise.',
  bali: 'Bali is where your subconscious wanted to go. Sun, presence, the feeling that right now is enough.',
  mexicocity: 'Mexico City — warmth, chaos, life at full volume. Your choices said you are ready for all of it.',
  copenhagen: 'Copenhagen. Clean, quiet, honest. Your instincts chose a place where it is okay to just be still.'
};

const city = parsed.city || 'lisbon';
const emotion = parsed.emotion || 'melancholy';
return [{ json: { emotion, city, biasMessage: biasMessages[city] || biasMessages.lisbon } }];
